// Sistema de logs seguros - apenas em desenvolvimento
const isDevelopment = process.env.NODE_ENV === 'development';

const logger = {
  // Log seguro - não mostra dados sensíveis
  info: (message, ...args) => {
    if (isDevelopment) {
      console.log(`[INFO] ${message}`, ...args);
    }
  },
  
  // Log de erro seguro
  error: (message, error) => {
    if (isDevelopment) {
      console.error(`[ERROR] ${message}`, error?.message || error);
    }
  },
  
  // Log de debug - NUNCA em produção
  debug: (message, ...args) => {
    if (isDevelopment) {
      console.log(`[DEBUG] ${message}`, ...args);
    }
  },
  
  // Log seguro para dados sensíveis - apenas status
  secure: (message, status = 'OK') => {
    if (isDevelopment) {
      console.log(`[SECURE] ${message} - Status: ${status}`);
    }
  },
  
  // Log de warning
  warn: (message, ...args) => {
    if (isDevelopment) {
      console.warn(`[WARN] ${message}`, ...args);
    }
  }
};

export default logger;
